$(document).ready(function () {

  //Main Banner mostrar/esconder botoes ao passar por cima
  $(".main-slider-container").hover(
    function () {
      $(".navigation-arrow-left").addClass("active");
      $(".navigation-arrow-right").addClass("active");
      $(".navigation-tracker-main").addClass("active");
    },
    function () {
      $(".navigation-arrow-left").removeClass("active");
      $(".navigation-arrow-right").removeClass("active");
      $(".navigation-tracker-main").removeClass("active");
    }
  );

  //Slider do Main Banner
  function mainNavigation(slider) {
    let wrapper, dots, arrowLeft, arrowRight;

    function markup(remove) {
      wrapperMarkup(remove);
      dotMarkup(remove);
      arrowMarkup(remove);
    }

    function removeElement(elment) {
      elment.parentNode.removeChild(elment);
    }
    function createDiv(className) {
      var div = document.createElement("div");
      var classNames = className.split(" ");
      classNames.forEach((name) => div.classList.add(name));
      return div;
    }

    function arrowMarkup(remove) {
      if (remove) {
        removeElement(arrowLeft);
        removeElement(arrowRight);
        return;
      }
      arrowLeft = createDiv("navigation-arrow-left");
      arrowLeft.addEventListener("click", () => slider.prev());
      arrowRight = createDiv("navigation-arrow-right");
      arrowRight.addEventListener("click", () => slider.next());

      wrapper.appendChild(arrowLeft);
      wrapper.appendChild(arrowRight);
    }

    function wrapperMarkup(remove) {
      if (remove) {
        var parent = wrapper.parentNode;
        while (wrapper.firstChild)
          parent.insertBefore(wrapper.firstChild, wrapper);
        removeElement(wrapper);
        return;
      }
      wrapper = createDiv("navigation-wrapper");
      slider.container.parentNode.appendChild(wrapper);
      wrapper.appendChild(slider.container);
    }

    function dotMarkup(remove) {
      if (remove) {
        removeElement(dots);
        return;
      }
      dots = createDiv("navigation-tracker-main");
      slider.track.details.slides.forEach((_e, idx) => {
        var dot = createDiv("navigation-tracker-main-link");
        dot.addEventListener("click", () => slider.moveToIdx(idx));
        dots.appendChild(dot);
      });
      wrapper.appendChild(dots);
    }

    function updateClasses() {
      var slide = slider.track.details.rel;

      Array.from(dots.children).forEach(function (dot, idx) {
        idx === slide
          ? dot.classList.add("active")
          : dot.classList.remove("active");
      });
    }

    slider.on("created", () => {
      markup();
      updateClasses();
    });
    slider.on("optionsChanged", () => {
      console.log(2);
      markup(true);
      markup();
      updateClasses();
    });
    slider.on("slideChanged", () => {
      updateClasses();
    });
    slider.on("destroyed", () => {
      markup(true);
    });
  }

  var slider = new KeenSlider(
    "#main-slider",
    {
      loop: true,      
      defaultAnimation: {
        duration: 3000,
      },
    },
    [
      (slider) => {
        let timeout;
        let mouseOver = false;
        function clearNextTimeout() {
          clearTimeout(timeout);
        }
        function nextTimeout() {
          clearTimeout(timeout);
          if (mouseOver) return;
          timeout = setTimeout(() => {
            slider.next();
          }, 5000);
        }
        slider.on("created", () => {
          slider.container.addEventListener("mouseover", () => {
            mouseOver = true;
            clearNextTimeout();
          });
          slider.container.addEventListener("mouseout", () => {
            mouseOver = false;
            nextTimeout();
          });
          nextTimeout();
        });
        slider.on("dragStarted", clearNextTimeout);
        slider.on("animationEnded", nextTimeout);
        slider.on("updated", nextTimeout);
      },
      mainNavigation,
    ]
  );

  //Slider do Alerta
