    $('#input_login').on('input', function() {
        var inputVal = $(this).val();
        var isCpfPattern = /^\d{0,3}(\.\d{0,3}){0,2}-?\d{0,2}$/.test(inputVal);
        var isLetterThenNumericPattern = /^[A-Za-z]{0,3}\d{0,5}$/.test(inputVal);

        if (isCpfPattern) {
            $(this).unmask().mask('000.000.000-00'); // CPF mask
        } else if (isLetterThenNumericPattern) {
            $(this).unmask().mask('AAA00000'); // Mask with 3 letters followed by 5 numbers
        }
    });

