        $('.input-token').eq(0).val(paste[0]);
        $('.input-token').eq(1).val(paste[1]);
        $('.input-token').eq(2).val(paste[2]);
        $('.input-token').eq(3).val(paste[3]);
        $('.input-token').eq(4).val(paste[4]);
        $('.input-token').eq(5).val(paste[5]).focus();
    });

