function mostraOcultaObs(id,tipo){
	var idSpan = "#span_obs_" + tipo + "_" + id;
	var idDiv = "#div_obs_" + tipo + "_" + id;

	if($(idDiv).is(':visible')){
		$(idDiv).hide();
		$(idSpan).html("Mostrar mais");
	} else {
		$(idDiv).show();
		$(idSpan).html("Mostrar menos");
	}

	return false;
}

function carregaDetalhamento(idTr, objSpan){
	var trCompreende = "compreende_" + idTr;
	var trNaoCompreende = "ncompreende_" + idTr;
	var trObservacao = "observacao_" + idTr;

	var arTRsCompreende = $("tr[id^='compreende_']");
	var arTRsNaoCompreende = $("tr[id^='ncompreende_']");
	var arTRsObservacao = $("tr[id^='observacao_']");


	arTRsCompreende.each(function(e){
		if($(this).attr("id") != trCompreende){
			if($(this).is(':visible')){
				$(this).hide();
				var idSpan = "#span_link_detalhes_" + $(this).data('complemento_id');
				$(idSpan).html("<img src='https://www.econeteditora.com.br/ferramentas/regimes_cnae/img/ico_plus.png' />");
			}
		}
	})

	arTRsNaoCompreende.each(function(e){
		if($(this).attr("id") != trNaoCompreende){
			if($(this).is(':visible')){
				$(this).hide();
				var idSpan = "#span_link_detalhes_" + $(this).data('complemento_id');
				$(idSpan).html("<img src='https://www.econeteditora.com.br/ferramentas/regimes_cnae/img/ico_plus.png' />");
			}
		}
	});

	arTRsObservacao.each(function(e){
		if($(this).attr("id") != trObservacao){
			if($(this).is(':visible')){
				$(this).hide();
				var idSpan = "#span_link_detalhes_" + $(this).data('complemento_id');
				$(idSpan).html("<img src='https://www.econeteditora.com.br/ferramentas/regimes_cnae/img/ico_plus.png' />");
			}
		}
	});
	if($("#"+trCompreende).is(':visible')){
		$("#"+trCompreende).hide();
		$("#"+trNaoCompreende).hide();
		$("#"+trObservacao).hide();
		$(objSpan).html("<img src='https://www.econeteditora.com.br/ferramentas/regimes_cnae/img/ico_plus.png' />");
	} else {
		$("#"+trCompreende).show();
		$("#"+trNaoCompreende).show();
		$("#"+trObservacao).show();
		$(objSpan).html("<img src='https://www.econeteditora.com.br/ferramentas/regimes_cnae/img/ico_minus.png' />");
	}
}

