		$("#aba_1Cnae").attr('checked');
		
	}
}

function carregaAbas(strAba, intIdCnae, obj){
	$('.button_aba_primaria').each(function(){
		$(this).removeClass('button_aba_primaria_active');
	});

	$(obj).addClass('button_aba_primaria_active');
	

	$.ajax({
		url: 'abas.php',
		data: {'aba': strAba, 'idCnae': intIdCnae},
		success: function(data){
			$("#divRetorno").html(data);
		},
		complete: function(){
			$("#aba_1").click();
		}
	});
}

